INSERT INTO public.announcements (id, created_by, title, body, audience, created_at) VALUES ('a10acfe7-d405-43fb-a272-f3c6ef59cc4b', '4475d406-4e5a-484b-8a99-d10c625c6ebc', 'Welcome to Internship Program 2026', 'We are excited to welcome all interns and mentors to the 2026 internship program. Please ensure you complete your onboarding tasks within the first week.', 'all', '2026-03-29 21:34:16.473356');
INSERT INTO public.announcements (id, created_by, title, body, audience, created_at) VALUES ('fc9a2ad9-71f4-4dcf-b86b-40c0483a8d0b', 'f2e41f92-86da-47f1-9563-d07321742030', 'Intern Attendance Policy', 'All interns are required to mark attendance daily before 10 AM. Late entries will be marked accordingly.', 'interns_only', '2026-03-29 21:34:16.473356');
INSERT INTO public.announcements (id, created_by, title, body, audience, created_at) VALUES ('ebcd1c34-a2df-4a7d-9124-47cc72fe3b64', '4475d406-4e5a-484b-8a99-d10c625c6ebc', 'Mentor Evaluation Guidelines', 'Mentors are requested to evaluate assigned interns weekly and submit feedback through the portal.', 'mentors_only', '2026-03-29 21:34:16.473356');
INSERT INTO public.announcements (id, created_by, title, body, audience, created_at) VALUES ('23e34c89-e051-4712-97e8-f57dfa99fa36', 'f2e41f92-86da-47f1-9563-d07321742030', 'Holiday Notice', 'The office will remain closed on account of a public holiday this Friday. Attendance will not be required.', 'all', '2026-03-29 21:34:16.473356');
INSERT INTO public.announcements (id, created_by, title, body, audience, created_at) VALUES ('b9f1bf00-9c6c-4097-b60b-3cebe0dbcaeb', 'f2e41f92-86da-47f1-9563-d07321742030', 'AI/ML Training Session', 'A special training session on AI and Machine Learning will be conducted this Saturday at 11 AM in the seminar hall.', 'interns_only', '2026-03-29 21:34:16.473356');
